9234 bool BoUpSLP::isLoadCombineCandidate() const {
9235   // Peek through a final sequence of stores and check if all operations are
9236   // likely to be load-combined.
9237   unsigned NumElts = VectorizableTree[0]->Scalars.size();
9238   for (Value *Scalar : VectorizableTree[0]->Scalars) {
9239     Value *X;
9240     if (!match(Scalar, m_Store(m_Value(X), m_Value())) ||
9241         !isLoadCombineCandidateImpl(X, NumElts, TTI, /* MatchOr */ true))
9242       return false;
9243   }
9244   return true;
9245 }
