12638       E->buildAltOpShuffleMask(
12639           [E, this](Instruction *I) {
12640             assert(E->isOpcodeOrAlt(I) && "Unexpected main/alternate opcode");
12641             return isAlternateInstruction(I, E->getMainOp(), E->getAltOp(),
12642                                           *TLI);
12643           },
12644           Mask, &OpScalars, &AltScalars);
